//! Standing Wave Audio Entropy — DFT-based entropy harvesting for FOIL.
//!
//! Extracts standing wave patterns from f32 PCM audio or IQ samples,
//! applies a 10-layer amplituhedron filter, and harvests surviving
//! spectral bins as FOIL shape keys for the entropy cache.
//!
//! Lean: `Gnosis.StormAsStandingWave`, `Gnosis.WallingtonFoilBridge`
//!
//! The standing wave aeon (lucas(11) = 199) bounds the maximum
//! admissible patterns per batch. The FOIL triton gate tiles:
//! 199 = 3 * 66 + 1 (three phases * C(12,2) carriers + clinamen).

use crate::phyle_temporal_depth::{NoiseColor, CLOCK_PERIOD};
use rustfft::{num_complex::Complex, Fft, FftPlanner};
use std::sync::Arc;

pub const STANDING_WAVE_N_FFT: usize = 2048;
pub const STANDING_WAVE_HOP: usize = 512;
pub const STANDING_WAVE_BINS: usize = STANDING_WAVE_N_FFT / 2 + 1;
pub const STANDING_WAVE_AEON: usize = 199;
pub const GNOSIS_TIME_HOPS: usize = 5;
pub const TRITON: usize = CLOCK_PERIOD;

pub const FIBONACCI_HASH_MULTIPLIER: u64 = 11_400_714_819_323_198_485;

#[derive(Clone, Debug)]
pub struct StandingWaveResult {
    pub dominant_bin: u16,
    pub dominant_power: f32,
    pub total_power: f32,
    pub spectral_entropy: f32,
    pub concentration: f32,
    pub spectral_slope: f32,
    pub noise_color: NoiseColor,
    pub is_standing_wave: bool,
    pub is_transient: bool,
}

#[derive(Clone, Debug)]
pub struct StandingWaveAnalysis {
    pub windows: Vec<StandingWaveResult>,
    pub surviving_indices: Vec<usize>,
    pub entropy_keys: Vec<u64>,
    pub tri_channel: Option<TriChannelEntropy>,
    pub death_stats: [(usize, usize); 10],
    pub entropy_pulse_period_s: Option<f32>,
    pub noise_histogram: [usize; 4],
    pub duration_s: f32,
}

pub struct StandingWaveDFT {
    fft: Arc<dyn Fft<f32>>,
    hann: Vec<f32>,
}

impl StandingWaveDFT {
    pub fn new() -> Self {
        let mut planner = FftPlanner::new();
        let fft = planner.plan_fft_forward(STANDING_WAVE_N_FFT);
        let hann: Vec<f32> = (0..STANDING_WAVE_N_FFT)
            .map(|i| {
                let denom = if STANDING_WAVE_N_FFT > 1 {
                    (STANDING_WAVE_N_FFT - 1) as f32
                } else {
                    1.0
                };
                0.5 * (1.0 - (std::f32::consts::TAU * i as f32 / denom).cos())
            })
            .collect();
        Self { fft, hann }
    }

    pub fn power_spectrum(&self, samples: &[f32]) -> Vec<f32> {
        let n = STANDING_WAVE_N_FFT;
        let mut buf: Vec<Complex<f32>> = (0..n)
            .map(|i| {
                let s = if i < samples.len() { samples[i] } else { 0.0 };
                let w = self.hann[i];
                Complex::new(s * w, 0.0)
            })
            .collect();
        self.fft.process(&mut buf);
        buf[..STANDING_WAVE_BINS]
            .iter()
            .map(|c| c.norm_sqr())
            .collect()
    }

    pub fn detect_standing_wave(&self, samples: &[f32]) -> StandingWaveResult {
        let power = self.power_spectrum(samples);
        let total_power: f32 = power.iter().sum();
        let (dominant_bin, dominant_power) = power
            .iter()
            .enumerate()
            .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
            .map(|(i, &p)| (i as u16, p))
            .unwrap_or((0, 0.0));

        let concentration = if total_power > 1e-15 {
            dominant_power / total_power
        } else {
            0.0
        };

        let spectral_entropy = compute_spectral_entropy(&power);
        let spectral_slope = compute_spectral_slope(&power);
        let noise_color = classify_noise(spectral_slope, concentration, spectral_entropy);
        let is_standing = concentration > 0.4 && spectral_entropy < 2.5;

        StandingWaveResult {
            dominant_bin,
            dominant_power,
            total_power,
            spectral_entropy,
            concentration,
            spectral_slope,
            noise_color,
            is_standing_wave: is_standing,
            is_transient: false,
        }
    }

    pub fn analyze(&self, samples: &[f32]) -> StandingWaveAnalysis {
        let n_windows = if samples.len() >= STANDING_WAVE_N_FFT {
            (samples.len() - STANDING_WAVE_N_FFT) / STANDING_WAVE_HOP + 1
        } else {
            0
        };

        let mut windows: Vec<StandingWaveResult> = Vec::with_capacity(n_windows);
        let mut rolling_power: Vec<f32> = Vec::new();

        for wi in 0..n_windows {
            let start = wi * STANDING_WAVE_HOP;
            let mut result =
                self.detect_standing_wave(&samples[start..start + STANDING_WAVE_N_FFT]);

            rolling_power.push(result.total_power);
            if rolling_power.len() > 10 {
                let recent = &rolling_power[rolling_power.len() - 11..rolling_power.len() - 1];
                let mean: f32 = recent.iter().sum::<f32>() / recent.len() as f32;
                result.is_transient = result.total_power > mean * 4.0;
            }
            windows.push(result);
        }

        let death_stats = amplituhedron_filter(&mut windows);
        let surviving_indices: Vec<usize> = windows
            .iter()
            .enumerate()
            .filter(|(_, w)| w.is_standing_wave)
            .map(|(i, _)| i)
            .collect();

        let entropy_keys = harvest_entropy_keys(&windows, &surviving_indices);
        let tri_channel = if !surviving_indices.is_empty() {
            Some(harvest_tri_channel_keys(&windows, &surviving_indices))
        } else {
            None
        };
        let entropy_pulse_period_s = detect_entropy_pulse(&windows);

        let mut noise_histogram = [0usize; 4];
        for w in &windows {
            match w.noise_color {
                NoiseColor::White => noise_histogram[0] += 1,
                NoiseColor::Pink => noise_histogram[1] += 1,
                NoiseColor::Brown => noise_histogram[2] += 1,
                NoiseColor::StandingWave => noise_histogram[3] += 1,
            }
        }

        let duration_s = samples.len() as f32 / 16000.0;

        StandingWaveAnalysis {
            windows,
            surviving_indices,
            entropy_keys,
            tri_channel,
            death_stats,
            entropy_pulse_period_s,
            noise_histogram,
            duration_s,
        }
    }
}

impl Default for StandingWaveDFT {
    fn default() -> Self {
        Self::new()
    }
}

fn compute_spectral_entropy(power: &[f32]) -> f32 {
    let total: f32 = power.iter().sum();
    if total < 1e-15 {
        return 0.0;
    }
    let mut entropy = 0.0f32;
    for &p in power {
        let prob = p / total;
        if prob > 1e-15 {
            entropy -= prob * prob.ln();
        }
    }
    entropy
}

fn compute_spectral_slope(power: &[f32]) -> f32 {
    let n = power.len();
    if n < 4 {
        return 0.0;
    }
    let mut sum_x = 0.0f64;
    let mut sum_y = 0.0f64;
    let mut sum_xy = 0.0f64;
    let mut sum_xx = 0.0f64;
    let mut count = 0usize;
    for i in 1..n {
        let x = (i as f64).ln();
        let p = power[i] as f64;
        if p > 1e-15 {
            let y = p.ln();
            sum_x += x;
            sum_y += y;
            sum_xy += x * y;
            sum_xx += x * x;
            count += 1;
        }
    }
    if count < 4 {
        return 0.0;
    }
    let cn = count as f64;
    let denom = cn * sum_xx - sum_x * sum_x;
    if denom.abs() < 1e-15 {
        return 0.0;
    }
    let slope = (cn * sum_xy - sum_x * sum_y) / denom;
    -slope as f32
}

fn classify_noise(slope: f32, concentration: f32, entropy: f32) -> NoiseColor {
    if concentration > 0.4 && entropy < 2.5 {
        return NoiseColor::StandingWave;
    }
    if slope < 0.5 {
        NoiseColor::White
    } else if slope < 1.5 {
        NoiseColor::Pink
    } else {
        NoiseColor::Brown
    }
}

fn amplituhedron_filter(windows: &mut Vec<StandingWaveResult>) -> [(usize, usize); 10] {
    let n = windows.len();
    let mut death_stats = [(0usize, 0usize); 10];
    let mut alive = vec![true; n];

    if n == 0 {
        return death_stats;
    }

    let global_mean: f32 = windows.iter().map(|w| w.total_power).sum::<f32>() / n as f32;

    // D1: Noise floor
    for i in 0..n {
        if windows[i].total_power < global_mean * 0.1 {
            alive[i] = false;
            death_stats[0].1 += 1;
        } else {
            death_stats[0].0 += 1;
        }
    }

    // D2: Entropy gate
    for i in 0..n {
        if !alive[i] {
            continue;
        }
        if windows[i].spectral_entropy > 4.0 {
            alive[i] = false;
            death_stats[1].1 += 1;
        } else {
            death_stats[1].0 += 1;
        }
    }

    // D3: Spectral drift
    for i in 0..n {
        if !alive[i] {
            continue;
        }
        let mut drifted = true;
        for j in i.saturating_sub(3)..=(i + 3).min(n - 1) {
            if j == i || !alive[j] {
                continue;
            }
            let diff =
                (windows[i].dominant_bin as i32 - windows[j].dominant_bin as i32).unsigned_abs();
            if diff < (STANDING_WAVE_N_FFT / 8) as u32 {
                drifted = false;
                break;
            }
        }
        if drifted && i > 3 && i + 3 < n {
            alive[i] = false;
            death_stats[2].1 += 1;
        } else {
            death_stats[2].0 += 1;
        }
    }

    // D4: Resonance grouping (assign group IDs, count sizes)
    let mut groups: Vec<Option<usize>> = vec![None; n];
    let mut group_id = 0usize;
    let mut in_group = false;
    for i in 0..n {
        if !alive[i] {
            in_group = false;
            continue;
        }
        if !in_group {
            group_id += 1;
            in_group = true;
        } else if i > 0 {
            let diff = (windows[i].dominant_bin as i32 - windows[i - 1].dominant_bin as i32)
                .unsigned_abs();
            if diff > 3 {
                group_id += 1;
            }
        }
        groups[i] = Some(group_id);
        death_stats[3].0 += 1;
    }

    // D5: Minimum persistence (group size >= TRITON)
    let mut group_sizes = std::collections::HashMap::new();
    for g in groups.iter().flatten() {
        *group_sizes.entry(*g).or_insert(0usize) += 1;
    }
    for i in 0..n {
        if !alive[i] {
            continue;
        }
        if let Some(g) = groups[i] {
            if group_sizes.get(&g).copied().unwrap_or(0) < TRITON {
                alive[i] = false;
                death_stats[4].1 += 1;
            } else {
                death_stats[4].0 += 1;
            }
        }
    }

    // D6: Spectral slope bounds
    for i in 0..n {
        if !alive[i] {
            continue;
        }
        if windows[i].spectral_slope < -0.5 || windows[i].spectral_slope > 3.0 {
            alive[i] = false;
            death_stats[5].1 += 1;
        } else {
            death_stats[5].0 += 1;
        }
    }

    // D7: Triton persistence (shell resolution)
    for i in 0..n {
        if !alive[i] {
            continue;
        }
        let shell_needed = match windows[i].noise_color.resolves_at_shell() {
            None => {
                alive[i] = false;
                death_stats[6].1 += 1;
                continue;
            }
            Some(s) => s as usize,
        };
        let frames_needed = TRITON * TRITON.pow(shell_needed as u32);
        if let Some(g) = groups[i] {
            let size = group_sizes.get(&g).copied().unwrap_or(0);
            if size < frames_needed {
                alive[i] = false;
                death_stats[6].1 += 1;
            } else {
                death_stats[6].0 += 1;
            }
        }
    }

    // D8: God formula (w = R - min(v,R) + 1 >= 2)
    let total_rounds = n as f32;
    let mut rejections = 0f32;
    for i in 0..n {
        if !alive[i] {
            rejections += 1.0;
            continue;
        }
        let weight = total_rounds - rejections.min(total_rounds) + 1.0;
        if weight < 2.0 {
            alive[i] = false;
            death_stats[7].1 += 1;
        } else {
            death_stats[7].0 += 1;
        }
    }

    // D9: Interference (neighbors same color = constructive)
    for i in 1..n.saturating_sub(1) {
        if !alive[i] {
            continue;
        }
        let mut score: i32 = 0;
        if alive[i.saturating_sub(1)] {
            if windows[i].noise_color == windows[i - 1].noise_color {
                score += 1;
            } else {
                score -= 1;
            }
        }
        if i + 1 < n && alive[i + 1] {
            if windows[i].noise_color == windows[i + 1].noise_color {
                score += 1;
            } else {
                score -= 1;
            }
        }
        if score < 0 {
            alive[i] = false;
            death_stats[8].1 += 1;
        } else {
            death_stats[8].0 += 1;
        }
    }

    // D10: Final convergence count
    for i in 0..n {
        if alive[i] {
            death_stats[9].0 += 1;
        }
    }

    // Mark surviving windows
    for i in 0..n {
        if !alive[i] {
            windows[i].is_standing_wave = false;
        }
    }

    death_stats
}

fn harvest_entropy_keys(windows: &[StandingWaveResult], surviving: &[usize]) -> Vec<u64> {
    surviving
        .iter()
        .take(STANDING_WAVE_AEON)
        .map(|&i| {
            let w = &windows[i];
            let raw = (w.dominant_bin as u64) << 32 | (w.concentration.to_bits() as u64);
            raw.wrapping_mul(FIBONACCI_HASH_MULTIPLIER)
        })
        .collect()
}

fn detect_entropy_pulse(windows: &[StandingWaveResult]) -> Option<f32> {
    if windows.len() < 20 {
        return None;
    }
    let entropy_series: Vec<f32> = windows.iter().map(|w| w.spectral_entropy).collect();
    let smoothed: Vec<f32> = entropy_series
        .windows(TRITON)
        .map(|w| w.iter().sum::<f32>() / TRITON as f32)
        .collect();

    let max_lag = (smoothed.len() / 2).min(5000);
    if max_lag < 10 {
        return None;
    }

    let mean: f32 = smoothed.iter().sum::<f32>() / smoothed.len() as f32;
    let var: f32 = smoothed.iter().map(|&x| (x - mean) * (x - mean)).sum();
    if var < 1e-15 {
        return None;
    }

    let mut best_lag = 0usize;
    let mut best_corr = 0.0f32;
    for lag in 5..max_lag {
        let mut sum = 0.0f32;
        for i in 0..(smoothed.len() - lag) {
            sum += (smoothed[i] - mean) * (smoothed[i + lag] - mean);
        }
        let corr = sum / var;
        if corr > best_corr {
            best_corr = corr;
            best_lag = lag;
        }
    }

    if best_corr > 0.1 {
        Some(best_lag as f32 * STANDING_WAVE_HOP as f32 / 16000.0)
    } else {
        None
    }
}

// ═══════════════════════════════════════════════════════════════════
// THREE-CHANNEL FORK/RACE/FOLD ENTROPY
//
// The equilateral triangle has three diagonals, each 120 degrees apart.
// Each diagonal is a FOIL channel:
//   Fork (radial):    bins 0..BINS/3        (low frequency, initiation)
//   Race (CW diag):   bins BINS/3..2*BINS/3 (mid frequency, competition)
//   Fold (CCW diag):  bins 2*BINS/3..BINS   (high frequency, resolution)
//
// Three channels of standing wave entropy, braided together.
// Total rate: 3x single-channel = lucas(6) = 18 bits/s from one source.
// ═══════════════════════════════════════════════════════════════════

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum FoilChannel {
    Fork, // low band (0 - 2.7 kHz)
    Race, // mid band (2.7 - 5.3 kHz)
    Fold, // high band (5.3 - 8 kHz)
}

impl FoilChannel {
    pub fn bin_range(&self) -> (usize, usize) {
        let third = STANDING_WAVE_BINS / 3;
        match self {
            Self::Fork => (0, third),
            Self::Race => (third, third * 2),
            Self::Fold => (third * 2, STANDING_WAVE_BINS),
        }
    }

    pub fn phase_clock_value(&self) -> u8 {
        match self {
            Self::Fork => 1,  // ForkFuture
            Self::Race => 0,  // RaceFoldPresent
            Self::Fold => 11, // VentInterferePast (keystone)
        }
    }
}

#[derive(Clone, Debug)]
pub struct TriChannelEntropy {
    pub fork_keys: Vec<u64>,
    pub race_keys: Vec<u64>,
    pub fold_keys: Vec<u64>,
    pub fork_dominant_bin: u16,
    pub race_dominant_bin: u16,
    pub fold_dominant_bin: u16,
}

pub fn harvest_tri_channel_keys(
    windows: &[StandingWaveResult],
    surviving: &[usize],
) -> TriChannelEntropy {
    let fork_range = FoilChannel::Fork.bin_range();
    let race_range = FoilChannel::Race.bin_range();
    let fold_range = FoilChannel::Fold.bin_range();

    let mut fork_keys = Vec::new();
    let mut race_keys = Vec::new();
    let mut fold_keys = Vec::new();
    let mut fork_best = (0u16, 0.0f32);
    let mut race_best = (0u16, 0.0f32);
    let mut fold_best = (0u16, 0.0f32);

    for &i in surviving.iter().take(STANDING_WAVE_AEON) {
        let w = &windows[i];
        let bin = w.dominant_bin as usize;

        let (keys, best) = if bin >= fork_range.0 && bin < fork_range.1 {
            (&mut fork_keys, &mut fork_best)
        } else if bin >= race_range.0 && bin < race_range.1 {
            (&mut race_keys, &mut race_best)
        } else {
            (&mut fold_keys, &mut fold_best)
        };

        let raw = (w.dominant_bin as u64) << 32 | (w.concentration.to_bits() as u64);
        keys.push(raw.wrapping_mul(FIBONACCI_HASH_MULTIPLIER));

        if w.dominant_power > best.1 {
            *best = (w.dominant_bin, w.dominant_power);
        }
    }

    TriChannelEntropy {
        fork_keys,
        race_keys,
        fold_keys,
        fork_dominant_bin: fork_best.0,
        race_dominant_bin: race_best.0,
        fold_dominant_bin: fold_best.0,
    }
}

/// Convert IQ u8 pairs (RTL-SDR format) to f32 PCM for analysis.
pub fn iq_to_pcm(iq: &[u8]) -> Vec<f32> {
    let pairs = iq.len() / 2;
    let mut pcm = Vec::with_capacity(pairs);
    for i in 0..pairs {
        let re = (iq[i * 2] as f32 - 128.0) / 128.0;
        let im = (iq[i * 2 + 1] as f32 - 128.0) / 128.0;
        pcm.push((re * re + im * im).sqrt());
    }
    pcm
}
